import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/88-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/88-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/88-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 为，我们提出在特伦特付款的建议，简直是对他的嘲弄。因此，诸位大人 不应再坚持之前给我的指示。请诸位大人无论如何，都要尽快给我送来明 确的新指示。诸位大人必能做出英明的抉择，因为我已经把这里的情况都 向诸位详细禀明。我知道的情况，诸位大人也都知悉。听说道路已经封 锁，我实在非常遗憾。这样，信件就不能及时到达这里，而目前的情况又 急需诸位大人的回信。所以，我请求诸位大人把信件复制成多个副本，并 由不同路线寄送。同时派出步行和骑马的信使，以确保至少有一人能把信 件送到我这里。我本来想让马基雅维利回到宫廷，就像我之前派他去特伦 特一样。但是，这样就违反了皇帝的命令，可能会惹恼宫廷。如此，也许 我们都不能得到批准，继续留在德意志。所以，我只好遵命而行了。 我今天就要离开这里前往梅拉诺。在这之前，我必须告诉诸位大人我 和一些朝中要员的谈话。他们显然是想让我看出皇帝在这次战事中的光 明前景。于是他们向我保证，1个月之内我们必能看到，皇帝以其英明神 武，在战事中势如破竹。但是， 一些不是那么位高权重的人，则有不同说 法。他们说，皇帝此次行动是为了向国民表示，此次战事需要民众更大的 支持。而且这样的支持，对国民来说是一件光荣的事。不过，也有人对此 事另有猜测。他们说，皇帝想要取胜相当困难。如果教皇不愿给皇帝资金 支持，那么他就要被迫与笃信王法国国王陛下或威尼斯人签订协议。而且 他目前的所作所为，目的就是要给帝国一个理由，证明他不得不和法国或 威尼斯达成协议。最后，还有一些人把皇帝这些行动的原因，归结为我在 上一封信中所说的理由。现在，无论这些说法哪个可能是正确的，诸位大 人都可以仔细验明，并得出更为准确的结论。但是，诸位大人也要深思， 如果不与皇帝达成任何协议，万一他顺利地通过哪条路线进入意大利，那 将会有什么结局。这是可能发生的，因为如果法国国王对所有人的表现都 不满意，那么他就可能让大家都任凭皇帝的意思处理。 所有这些事情，诸位大人必能睿智地做出最佳判断，得出适当的结 论，并下达相应的命令。",-1),e("p",null,"Opere complete di Niccolò Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
